import React from 'react';
import OwlCarousel from 'react-owl-carousel';
import Trendingcard from './Trendingcard';
import ss1 from './images/ss1.jpeg';
import ss2 from './images/ss2.jpeg';
import ss3 from './images/ss3.jpeg';
import ss4 from './images/ss4.jpeg';
import ss5 from './images/ss5.jpeg';
import ss6 from './images/ss6.jpg';
// import ss7 from './images/ss7.jpg';


const Trending =() =>{

    var series=[
        {
            S1:"Sweet Home",
            S2:" Elite",
            S3:"Dark Desire",
            S4:"Fame Game",
            S5:"Twenty Five Twenty One",
            S6:"It's Okay To Not Be Okay"
        }
    ]


    return(

        <section id="trending">
            <div class="container-fluid">
                <div class="row">
                    <div class="col-12">

                        <h2 class="text-center text-white fw-bold py-5 font2">Trending Series</h2>

                        <OwlCarousel className='owl-theme'  autoplay loop dotsClass='none'
                        responsive= {
                            {
                                '0':{
                                    items: 1
                                },
                                '768': {
                                    items: 2
                                },
                                '1200': {
                                    items: 3
                                }
                            }
                            
                        }
                        >
                            <div class='item'>   
                                <Trendingcard seriesname={series[0].S1} imgs={ss1}/>
                            </div>
                            <div class='item'>   
                                <Trendingcard seriesname={series[0].S3} imgs={ss2}/>
                            </div>
                            <div class='item'>   
                                <Trendingcard seriesname={series[0].S2} imgs={ss3}/>
                            </div>
                            <div class='item'> 
                                <Trendingcard seriesname={series[0].S4} imgs={ss4}/>
                            </div>
                            <div class='item'> 
                                <Trendingcard seriesname={series[0].S5} imgs={ss5}/>
                            </div>
                            <div class='item'>
                                <Trendingcard seriesname={series[0].S6} imgs={ss6}/>
                            </div>
                        </OwlCarousel>
                    </div>
                </div>
            </div>
        </section>
    );
} 
export default Trending;
