import logo from './images/logo.png'
const Hero =() =>{
    return(
        <section id="hero-section">
            <div className="container-fluid">
                <div className="row">
                    <div className="col-12 p-0">
                        <nav class="navbar navbar-expand-lg bg-transparent">
                        <div class="container-fluid">
                            <a class="navbar-brand" href="#"><img src={logo} class="logo"></img></a>
                            <button class="navbar-toggler" type="button" data-bs-toggle="collapse" data-bs-target="#navbarNavAltMarkup" aria-controls="navbarNavAltMarkup" aria-expanded="false" aria-label="Toggle navigation">
                            <span class="navbar-toggler-icon"></span>
                            </button>
                            <div class="collapse navbar-collapse" id="navbarNavAltMarkup">
                            <div class="navbar-nav ms-auto">
                                <a class="nav-link text-white font2" aria-current="page" href="#">Home</a>
                                <a class="nav-link text-white font2" href="#">Features</a>
                                <a class="nav-link text-white font2" href="#">Pricing</a>
                               
                            </div>
                            </div>
                        </div>
                        </nav>
                    </div>
                </div>
                <div className='row py-5'>
              <div className='col-12 text-center p-0'>
                <h2 className='display-3 py-5 text-white fw-bold font1'>Unlimited movies, TV shows, and more.</h2>
                <h3 className='text-white pb-5 fs-2 font2'>Watch anywhere. Cancel anytime.</h3>
                <h4 className='text-white pb-3 font3'>Ready to watch? Enter your email to create or restart your membership</h4>
                <div className="py-4 " id='mailid'>
                  <input type='mail' class="mx-2" placeholder='email address'></input>
                  <button class="mx-2">Get Started</button>
                </div>
              </div>
            </div>
            </div>
        </section>
        
    );
}
export default Hero;