const Trendingcard =(props) =>{

    return(
        <div class="card border-0 rounded-0 mx-md-3 bg-transparent">
            <img src={props.imgs} class="card-img-top" alt="Series"/>
            <div class="card-body text-center">
                <h5 class="py-3 fw-bold text-white font1">{props.seriesname}</h5>
                
                
            </div>
        </div>

    );
}
export default Trendingcard;
